INSERT INTO fbi_code (code, title, description, crime_against) VALUES
('01A','Homicide 1st & 2nd Degree','The killing of one human being by another.','Persons'),
('01B','Involuntary Manslaughter','The killing of another person through negligence.','Persons'),
('3','Robbery','The taking or attempting to take anything of value under confrontational circumstances from the control, custody, or care of another person by force or threat of force or violence and/or by putting the victim in fear of immediate harm.','Property'),
('04A','Aggravated Assault','An unlawful attack by one person upon another wherein the offender displays a weapon in a threatening manner. Placing someone in reasonable apprehension of receiving a battery.','Persons'),
('04B','Aggravated Battery','An unlawful attack by one person upon another wherein the offender uses a weapon or the victim suffers obvious severe or aggravated bodily injury involving apparent broken bones, loss of teeth, possible internal injury, severe laceration, or loss of consciousness.','Persons'),
('5','Burglary','The unlawful entry into a building or other structure with the intent to commit a felony or a theft.','Property'),
('13','Stolen Property','Receiving, buying, selling, possessing, concealing, or transporting any property with the knowledge that it has been unlawfully taken, as by Burglary, Embezzlement, Fraud, Larceny, Robbery, etc.','Property'),
('14','Vandalism','To willfully or maliciously destroy, damage, deface, or otherwise injure real or personal property without the consent of the owner or the person having custody or control of it.','Property'),
('15','Weapons Violation','The violation of laws or ordinances prohibiting the manufacture, sale, purchase, transportation, possession, concealment, or use of firearms, cutting instruments, explosives, incendiary devices, or other deadly weapons.','Society'),
('18','Drug Abuse','The violation of laws prohibiting the production, distribution, and/or use of certain controlled substances and the equipment or devices utilized in their preparation and/or use.','Society'),
('19','Gambling','To unlawfully bet or wager money or something else of value; assist, promote, or operate a game of chance for money or some other stake; possess or transmit wagering information; manufacture, sell, purchase, possess, or transport gambling equipment, devices, or goods; or tamper with the outcome of a sporting event or contest to gain a gambling advantage.','Society'),
('20','Offenses Against Family','Unlawful, nonviolent acts by a family member (or legal guardian) that threaten the physical, mental, or economic well-being or morals of another family member and that are not classifiable as other offenses, such as Assault, Incest, Statutory Rape, etc.','Persons and Society'),
('22','Liquor License','The violation of laws or ordinances prohibiting the manufacture, sale, purchase, transportation, possession, or use of alcoholic beverages.','Society'),
('24','Disorderly Conduct','Any behavior that tends to disturb the public peace or decorum, scandalize the community, or shock the public sense of morality.','Society'),
('26','Misc Non-Index Offense','The violation of miscellaneous laws or ordinances.','Society'),
('6','Larceny','The unlawful taking, carrying, leading, or riding away of property from the possession or constructive possession of another person.','Property'),
('7','Motor Vehicle Theft','The theft of a motor vehicle.','Property'),
('08A','Simple Assault','An unlawful physical attack by one person upon another where neither the offender displays a weapon, nor the victim suffers obvious severe or aggravated bodily injury involving apparent broken bones, loss of teeth, possible internal injury, severe laceration, or loss of consciousness.','Persons'),
('08B','Simple Battery','A person commits battery if he intentionally or knowingly without legal justification and by any means, (1) causes bodily harm to an individual or (2) makes physical contact of an insulting or provoking nature with an individual.','Persons'),
('9','Arson','To unlawfully and intentionally damage or attempt to damage any real or personal property by fire or incendiary device.','Property'),
('10','Forgery & Counterfeiting','The altering, copying, or imitation of something, without authority or right, with the intent to deceive or defraud by passing the copy or thing altered or imitated as that which is original or genuine or the selling, buying, or possession of an altered, copied, or imitated thing with the intent to deceive or defraud.','Property'),
('11','Fraud','The intentional perversion of the truth for the purpose of inducing another person or other entity in reliance upon it to part with something of value or to surrender a legal right.','Property'),
('12','Embezzlement','The unlawful misappropriation by an offender to his/her own use or purpose of money, property, or some other thing of value entrusted to his/her care, custody, or control.','Property');
