-- 1. community_area (no dependencies)
CREATE TABLE community_area (
    area_number         INTEGER      PRIMARY KEY,
    community_area_name VARCHAR(100) NOT NULL,
    side                VARCHAR(50)
);;

-- 2. district (no dependencies)
CREATE TABLE district (
    district_number INTEGER      PRIMARY KEY,
    name            VARCHAR(100),
    address         VARCHAR(200),
    zip_code        VARCHAR(10),
    commander       VARCHAR(100),
    email           VARCHAR(150),
    phone           VARCHAR(20),
    fax             VARCHAR(20),
    tty             VARCHAR(20),
    twitter         VARCHAR(100)
);;

-- 3. fbi_code (no dependencies)
CREATE TABLE fbi_code (
    code          VARCHAR(5)   PRIMARY KEY,
    title         VARCHAR(100),
    description   TEXT,
    crime_against VARCHAR(50)
);;

-- 4. iucr (no dependencies)
CREATE TABLE iucr (
    iucr                  VARCHAR(5)   PRIMARY KEY,
    primary_description   VARCHAR(100),
    secondary_description VARCHAR(150),
    index_code            CHAR(1)
);;

-- 5. ward (no dependencies)
CREATE TABLE ward (
    ward_no               INTEGER      PRIMARY KEY,
    alderman_first_name   VARCHAR(50),
    alderman_last_name    VARCHAR(50),
    alderman_name_suffix  VARCHAR(20),
    ward_office_address   VARCHAR(200),
    ward_office_zip       VARCHAR(10),
    ward_email            VARCHAR(150),
    ward_office_phone     VARCHAR(20),
    ward_office_fax       VARCHAR(20),
    city_hall_office_room VARCHAR(20),
    city_hall_office_phone VARCHAR(20),
    city_hall_office_fax  VARCHAR(20)
);;

-- 6. neighborhood (depends on community_area)
CREATE TABLE neighborhood (
    neighborhood VARCHAR(100) PRIMARY KEY,
    area_number  INTEGER REFERENCES community_area(area_number)
);;

-- 7. crime (depends on iucr, district, ward, community_area, fbi_code)
CREATE TABLE crime (
    crime_id             BIGINT       PRIMARY KEY,
    case_number          VARCHAR(20),
    date                 TIMESTAMP,
    block                VARCHAR(100),
    iucr                 VARCHAR(5)   REFERENCES iucr(iucr),
    location_description  VARCHAR(150),
    arrest               BOOLEAN,
    domestic             BOOLEAN,
    beat                 INTEGER,
    district             INTEGER      REFERENCES district(district_number),
    ward                 INTEGER      REFERENCES ward(ward_no),
    community_area       INTEGER      REFERENCES community_area(area_number),
    fbi_code             VARCHAR(5)   REFERENCES fbi_code(code),
    latitude             NUMERIC(9,6),
    longitude            NUMERIC(9,6)
);;








